import{_ as r,C as h,o as e,c as s,a2 as a,b as n,w as o,a as i,E as u,a3 as d}from"./chunks/framework.Crpw6aS5.js";const x=JSON.parse('{"title":"高管薪酬与激励","description":"期权激励如何扭曲行为，巴菲特的薪酬观","frontmatter":{"title":"高管薪酬与激励","description":"期权激励如何扭曲行为，巴菲特的薪酬观"},"headers":[],"relativePath":"02_concepts/executive-compensation.md","filePath":"02_concepts/executive-compensation.md"}'),q={name:"02_concepts/executive-compensation.md"};function c(p,t,b,f,m,_){const l=h("Mermaid");return e(),s("div",null,[t[1]||(t[1]=a('<h1 id="高管薪酬与激励" tabindex="-1">高管薪酬与激励 <a class="header-anchor" href="#高管薪酬与激励" aria-label="Permalink to &quot;高管薪酬与激励&quot;">​</a></h1><blockquote><p>&quot;大多数CEO薪酬方案的设计，是为了在任何情况下都给CEO支付高薪。&quot; —— <a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>高管薪酬是现代公司治理中最具争议的议题之一。巴菲特在1985、1992、1998、2002、2003、2008、2016年的股东信中反复深入讨论期权激励的利弊。他是伯克希尔薪酬制度的总设计师，也是华尔街&quot;标准&quot;薪酬实践最激烈的批评者。</p><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="/01_letters/1985年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">首次详细讨论期权激励问题</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/1992年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">期权成本的问题</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/1998年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">期权的激励扭曲问题</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2002年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">期权会计问题</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2003年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">批评高薪顾问公司</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2008年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">经济危机中的薪酬问题</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2016年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">关于伯克希尔的薪酬原则</td></tr></tbody></table><hr><h2 id="一、期权激励的问题" tabindex="-1">一、期权激励的问题 <a class="header-anchor" href="#一、期权激励的问题" aria-label="Permalink to &quot;一、期权激励的问题&quot;">​</a></h2><p>巴菲特在1985年信中首次系统分析期权激励的缺陷：</p><blockquote><p>&quot;在典型的期权计划中，CEO可以在股价下跌时稳坐钓鱼台——他们的奖金与股价表现无关。如果他们把公司搞砸了，期权仍然有效，可以等到市场好转时行权。这种激励是向下的，不是向上的。&quot;</p></blockquote><blockquote><p>&quot;真正的问题是：CEO的薪酬应该与他们的表现挂钩。不幸的是，大多数期权计划只是假装做到了这一点。&quot;</p></blockquote><hr><h2 id="二、为什么期权成本被忽视" tabindex="-1">二、为什么期权成本被忽视 <a class="header-anchor" href="#二、为什么期权成本被忽视" aria-label="Permalink to &quot;二、为什么期权成本被忽视&quot;">​</a></h2><p>1992年，巴菲特批评了期权会计规则：</p><blockquote><p>&quot;大多数公司发行股票期权时不将任何成本计入收益表。这意味着，即使期权最终价值数十亿美元，它们也不会减少报告的每股收益。&quot;</p></blockquote><blockquote><p>&quot;这是一种会计上的自我欺骗。公司在员工工资上精打细算，但通过期权支付数十亿美元时，却不计入成本。&quot;</p></blockquote><hr><h2 id="三、激励如何扭曲行为" tabindex="-1">三、激励如何扭曲行为 <a class="header-anchor" href="#三、激励如何扭曲行为" aria-label="Permalink to &quot;三、激励如何扭曲行为&quot;">​</a></h2><p>巴菲特1998年的分析更为深刻：</p><blockquote><p>&quot;期权激励不仅不能把管理者的利益与股东利益对齐，有时甚至会产生反效果。当管理者知道他们的财富与股价挂钩时，他们会做出短期决策来推高股价——即使这损害了公司的长期价值。&quot;</p></blockquote><blockquote><p>&quot;典型的股票期权安排不会定期增加期权价格以补偿留存收益正在积累公司财富的事实。实际上，十年期期权、低股息支付率和复利的组合可以为一位只是在其工作中原地踏步的经理人提供丰厚的收益。&quot;</p></blockquote><blockquote><p>&quot;愤世嫉俗者甚至可能注意到，当对业主的支付被压低时，持有期权的经理人的利润增加。&quot;</p></blockquote><hr><h2 id="四、经济危机中的薪酬问题" tabindex="-1">四、经济危机中的薪酬问题 <a class="header-anchor" href="#四、经济危机中的薪酬问题" aria-label="Permalink to &quot;四、经济危机中的薪酬问题&quot;">​</a></h2><p>2008年金融危机后，巴菲特批评了那些导致危机的薪酬制度：</p><blockquote><p>&quot;这次危机的根本原因之一，是太多华尔街高管的薪酬与短期收益挂钩，而与长期风险无关。他们被激励去冒险——赢了是自己的，亏了是股东和纳税人的。&quot;</p></blockquote><blockquote><p>&quot;薪酬方案应该让管理者像所有者一样思考和行动。当管理者真正拥有公司的一部分时，他们做出的决策会有所不同。&quot;</p></blockquote><hr><h2 id="五、伯克希尔的薪酬原则" tabindex="-1">五、伯克希尔的薪酬原则 <a class="header-anchor" href="#五、伯克希尔的薪酬原则" aria-label="Permalink to &quot;五、伯克希尔的薪酬原则&quot;">​</a></h2><p>伯克希尔的薪酬制度与华尔街截然不同：</p><blockquote><p>&quot;在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，我们不给CEO发放股票期权。我们给的是伯克希尔的股份——真正的所有权。&quot;</p></blockquote><blockquote><p>&quot;我们的高管薪酬不是为了与市场竞争。我们寻找的是那些以工作本身为动力的人。那些为了钱而工作的人，通常不会成为我们想要的管理者。&quot;</p></blockquote><hr><h2 id="六、代理问题的延伸" tabindex="-1">六、代理问题的延伸 <a class="header-anchor" href="#六、代理问题的延伸" aria-label="Permalink to &quot;六、代理问题的延伸&quot;">​</a></h2><p>巴菲特将期权激励问题与更广泛的代理问题联系起来：</p><blockquote><p>&quot;薪酬顾问公司知道他们的客户是谁——是聘请他们的CEO，而不是股东。这种利益冲突是系统性缺陷。&quot;</p></blockquote><blockquote><p>&quot;最终，解决薪酬问题的最好办法是：董事会真正独立，真正为股东服务。但这在大多数公司还没有发生。&quot;</p></blockquote><hr><h2 id="主题关联" tabindex="-1">主题关联 <a class="header-anchor" href="#主题关联" aria-label="Permalink to &quot;主题关联&quot;">​</a></h2>',39)),(e(),n(d,null,{default:o(()=>[u(l,{id:"mermaid-196",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E9%AB%98%E7%AE%A1%E8%96%AA%E9%85%AC%5D%20--%3E%20B%5B%E4%BB%A3%E7%90%86%E9%97%AE%E9%A2%98%5D%0A%20%20%20%20A%20--%3E%20C%5B%E5%85%AC%E5%8F%B8%E6%B2%BB%E7%90%86%5D%0A%20%20%20%20A%20--%3E%20D%5B%E7%AE%A1%E7%90%86%E5%B1%82%5D%0A%20%20%20%20A%20--%3E%20E%5B%E5%A3%B0%E8%AA%89%5D%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[i(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<hr><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="/search.html?q=公司治理">公司治理</a> - 董事会与代理问题</li><li><a href="/search.html?q=管理层">管理层</a> - 优秀管理者的特征</li><li><a href="/search.html?q=声誉">声誉</a> - 诚信与激励机制</li></ul><hr><p><em>本页面整理自<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>致股东信原文（1957-2024年），<a href="/search.html?q=慢慢变富的卡尔">慢慢变富的卡尔</a>编辑整理</em></p>',5))])}const E=r(q,[["render",c]]);export{x as __pageData,E as default};
